import java.io.*;

public class SecureCommandExecution {

    public static void main(String[] args) {
        try {
            // Simulating safe user input
            String userInput = "example.txt";

            // Validate and sanitize user input before using it in the command
            if (!userInput.matches("[a-zA-Z0-9._-]+")) {
                System.out.println("Invalid input");
                return;
            }

            // Construct the command using ProcessBuilder
            ProcessBuilder processBuilder = new ProcessBuilder();
            processBuilder.command("cat", userInput);

            // Start the process
            Process process = processBuilder.start();

            // Read output from the process
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

